function.body:
v_Display VARCHAR2(2000):='';
  v_sql VARCHAR2(2000):='';
BEGIN
  v_sql:='SELECT description FROM ' || p_tablename ||' WHERE '|| p_tablename || '_id = ''' || p_record_id || '''';
  EXECUTE IMMEDIATE v_sql INTO v_Display;
  RETURN v_Display;
EXCEPTION
WHEN OTHERS THEN
  RETURN '';
END SACGLD_FACTACCT_DES
